891 static KnownBits
892 getKnownBitsFromAndXorOr(const Operator *I, const APInt &DemandedElts,
893                          const KnownBits &KnownLHS, const KnownBits &KnownRHS,
894                          unsigned Depth, const SimplifyQuery &Q) {
895   unsigned BitWidth = KnownLHS.getBitWidth();
896   KnownBits KnownOut(BitWidth);
897   bool IsAnd = false;
898   bool HasKnownOne = !KnownLHS.One.isZero() || !KnownRHS.One.isZero();
899   Value *X = nullptr, *Y = nullptr;
900 
901   switch (I->getOpcode()) {
902   case Instruction::And:
903     KnownOut = KnownLHS & KnownRHS;
904     IsAnd = true;
905     // and(x, -x) is common idioms that will clear all but lowest set
906     // bit. If we have a single known bit in x, we can clear all bits
907     // above it.
908     // TODO: instcombine often reassociates independent `and` which can hide
909     // this pattern. Try to match and(x, and(-x, y)) / and(and(x, y), -x).
910     if (HasKnownOne && match(I, m_c_And(m_Value(X), m_Neg(m_Deferred(X))))) {
911       // -(-x) == x so using whichever (LHS/RHS) gets us a better result.
912       if (KnownLHS.countMaxTrailingZeros() <= KnownRHS.countMaxTrailingZeros())
913         KnownOut = KnownLHS.blsi();
914       else
915         KnownOut = KnownRHS.blsi();
916     }
917     break;
918   case Instruction::Or:
919     KnownOut = KnownLHS | KnownRHS;
920     break;
921   case Instruction::Xor:
922     KnownOut = KnownLHS ^ KnownRHS;
923     // xor(x, x-1) is common idioms that will clear all but lowest set
924     // bit. If we have a single known bit in x, we can clear all bits
925     // above it.
926     // TODO: xor(x, x-1) is often rewritting as xor(x, x-C) where C !=
927     // -1 but for the purpose of demanded bits (xor(x, x-C) &
928     // Demanded) == (xor(x, x-1) & Demanded). Extend the xor pattern
929     // to use arbitrary C if xor(x, x-C) as the same as xor(x, x-1).
930     if (HasKnownOne &&
931         match(I, m_c_Xor(m_Value(X), m_c_Add(m_Deferred(X), m_AllOnes())))) {
932       const KnownBits &XBits = I->getOperand(0) == X ? KnownLHS : KnownRHS;
933       KnownOut = XBits.blsmsk();
934     }
935     break;
936   default:
937     llvm_unreachable("Invalid Op used in 'analyzeKnownBitsFromAndXorOr'");
938   }
939 
940   // and(x, add (x, -1)) is a common idiom that always clears the low bit;
941   // xor/or(x, add (x, -1)) is an idiom that will always set the low bit.
942   // here we handle the more general case of adding any odd number by
943   // matching the form and/xor/or(x, add(x, y)) where y is odd.
944   // TODO: This could be generalized to clearing any bit set in y where the
945   // following bit is known to be unset in y.
946   if (!KnownOut.Zero[0] && !KnownOut.One[0] &&
947       (match(I, m_c_BinOp(m_Value(X), m_c_Add(m_Deferred(X), m_Value(Y)))) ||
948        match(I, m_c_BinOp(m_Value(X), m_Sub(m_Deferred(X), m_Value(Y)))) ||
949        match(I, m_c_BinOp(m_Value(X), m_Sub(m_Value(Y), m_Deferred(X)))))) {
950     KnownBits KnownY(BitWidth);
951     computeKnownBits(Y, DemandedElts, KnownY, Depth + 1, Q);
952     if (KnownY.countMinTrailingOnes() > 0) {
953       if (IsAnd)
954         KnownOut.Zero.setBit(0);
955       else
956         KnownOut.One.setBit(0);
957     }
958   }
959   return KnownOut;
960 }
